import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { B03Row } from '../../../services/analytics/models';
const B03DnPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<B03Row[]>([]);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getB03Dn({ year }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [year,dispatch]);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}>B03-DN</h1><p className={styles.subtitle}>Năm {year}</p></div>
        <div className={styles.headerActions}><Select value={String(year)} onChange={e=>setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Button variant="secondary" onClick={()=>exportExcel('/reports/financial/b03-dn/export-excel',{year},`B03-${year}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Chỉ tiêu</th><th className={styles.colRight}>Năm nay</th><th className={styles.colRight}>Năm trước</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i} className={r.isTotal?styles.rowTotal:undefined}><td>{r.code} — {r.name}</td><td className={styles.colRight}>{formatVnd(r.currentAmount)}</td><td className={styles.colRight}>{formatVnd(r.previousAmount)}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default B03DnPage;
